     6→import { TeamAuthProvider, useTeamAuth } from "@/contexts/TeamAuthContext";
     7→import { AdminAuthProvider } from "@/contexts/AdminAuthContext";
     8→import { ProtectedRoute } from "@/components/ProtectedRoute";
     9→import { AdminProtectedRoute } from "@/components/AdminProtectedRoute";
    10→import Login from "./pages/Login";
    11→import Signup from "./pages/Signup";
    12→import Dashboard from "./pages/Dashboard";
    13→import TrackSelection from "./pages/TrackSelection";
    14→import Leads from "./pages/Leads";
    15→import AdminLogin from "./pages/AdminLogin";
