    17→import Admin from "./pages/Admin";
    18→import AdminDisplay from "./pages/AdminDisplay";
    19→import NotFound from "./pages/NotFound";
    20→
    21→const queryClient = new QueryClient();
    22→
    23→function RootRedirect() {
    24→  const { team, loading } = useTeamAuth();
    25→  
    26→  if (loading) {
