     1→import { createContext, useContext, useEffect, useState, ReactNode } from 'react';
     2→import { User, Session } from '@supabase/supabase-js';
     3→import { supabase } from '@/integrations/supabase/client';
     4→
     5→interface AdminAuthContextType {
     6→  user: User | null;
     7→  session: Session | null;
     8→  isAdmin: boolean;
     9→  loading: boolean;
    10→  signIn: (email: string, password: string) => Promise<{ error: Error | null }>;
    11→  signOut: () => Promise<void>;
    12→}
    13→
    14→const AdminAuthContext = createContext<AdminAuthContextType | undefined>(undefined);
    15→
    16→export function AdminAuthProvider({ children }: { children: ReactNode }) {
    17→  const [user, setUser] = useState<User | null>(null);
    18→  const [session, setSession] = useState<Session | null>(null);
    19→  const [isAdmin, setIsAdmin] = useState(false);
    20→  const [loading, setLoading] = useState(true);
    21→
    22→  const checkAdminRole = async (userId: string) => {
    23→    const { data, error } = await supabase
    24→      .from('user_roles')
    25→      .select('role')
    26→      .eq('user_id', userId)
    27→      .eq('role', 'admin')
    28→      .maybeSingle();
    29→    
    30→    if (error) {
    31→      console.error('Error checking admin role:', error);
    32→      return false;
    33→    }
    34→    return !!data;
    35→  };
    36→
    37→  useEffect(() => {
    38→    // Set up auth state listener FIRST
    39→    const { data: { subscription } } = supabase.auth.onAuthStateChange(
    40→      (event, session) => {
    41→        setSession(session);
    42→        setUser(session?.user ?? null);
    43→        
    44→        // Defer admin check with setTimeout to prevent deadlock
    45→        if (session?.user) {
    46→          setTimeout(() => {
    47→            checkAdminRole(session.user.id).then(setIsAdmin);
    48→            setLoading(false);
    49→          }, 0);
    50→        } else {
    51→          setIsAdmin(false);
    52→          setLoading(false);
    53→        }
    54→      }
    55→    );
    56→
    57→    // THEN check for existing session
    58→    supabase.auth.getSession().then(({ data: { session } }) => {
    59→      setSession(session);
    60→      setUser(session?.user ?? null);
    61→      
    62→      if (session?.user) {
    63→        checkAdminRole(session.user.id).then((isAdminResult) => {
    64→          setIsAdmin(isAdminResult);
    65→          setLoading(false);
    66→        });
    67→      } else {
    68→        setLoading(false);
    69→      }
    70→    });
    71→
    72→    return () => subscription.unsubscribe();
    73→  }, []);
    74→
    75→  const signIn = async (email: string, password: string) => {
    76→    const { error } = await supabase.auth.signInWithPassword({ email, password });
    77→    return { error: error as Error | null };
    78→  };
    79→
    80→  const signOut = async () => {
    81→    await supabase.auth.signOut();
    82→    setUser(null);
    83→    setSession(null);
    84→    setIsAdmin(false);
    85→  };
    86→
    87→  return (
    88→    <AdminAuthContext.Provider value={{ user, session, isAdmin, loading, signIn, signOut }}>
    89→      {children}
    90→    </AdminAuthContext.Provider>
    91→  );
    92→}
    93→
    94→export function useAdminAuth() {
    95→  const context = useContext(AdminAuthContext);
    96→  if (context === undefined) {
    97→    throw new Error('useAdminAuth must be used within an AdminAuthProvider');
    98→  }
    99→  return context;
   100→}
