     1→import { useState, useEffect, useCallback } from 'react';
     2→import { supabase } from '@/integrations/supabase/client';
     3→import { toast } from 'sonner';
     4→
     5→interface TaskProgress {
     6→  task_key: string;
     7→  completed: boolean;
     8→  content: string | null;
     9→}
    10→
    11→interface TaskData {
    12→  completed: boolean;
    13→  content: string | null;
    14→}
    15→
    16→export function useSprintData(teamId: string | undefined) {
    17→  const [taskData, setTaskData] = useState<Map<string, TaskData>>(new Map());
    18→  const [loading, setLoading] = useState(true);
    19→  const [error, setError] = useState<string | null>(null);
    20→
    21→  const fetchData = useCallback(async () => {
    22→    if (!teamId) {
    23→      setLoading(false);
    24→      return;
    25→    }
    26→
    27→    try {
    28→      const { data: progressData, error: progressError } = await supabase
    29→        .from('task_progress')
    30→        .select('task_key, completed, content')
    31→        .eq('team_id', teamId);
    32→
    33→      if (progressError) throw progressError;
    34→
    35→      const dataMap = new Map<string, TaskData>();
    36→      progressData?.forEach((p) => {
    37→        dataMap.set(p.task_key, {
    38→          completed: p.completed,
    39→          content: p.content,
    40→        });
    41→      });
    42→      setTaskData(dataMap);
    43→    } catch (err: any) {
    44→      console.error('Error fetching sprint data:', err);
    45→      setError(err.message);
    46→    } finally {
    47→      setLoading(false);
    48→    }
    49→  }, [teamId]);
    50→
    51→  // Initial fetch
    52→  useEffect(() => {
    53→    fetchData();
    54→  }, [fetchData]);
    55→
    56→  // Subscribe to realtime updates for task progress
    57→  useEffect(() => {
    58→    if (!teamId) return;
    59→
    60→    const channel = supabase
    61→      .channel(`tasks-${teamId}`)
    62→      .on(
    63→        'postgres_changes',
    64→        {
    65→          event: '*',
    66→          schema: 'public',
    67→          table: 'task_progress',
    68→          filter: `team_id=eq.${teamId}`,
    69→        },
    70→        (payload) => {
    71→          if (payload.eventType === 'INSERT' || payload.eventType === 'UPDATE') {
    72→            const newData = payload.new as TaskProgress;
    73→            setTaskData((prev) => {
    74→              const updated = new Map(prev);
    75→              updated.set(newData.task_key, {
    76→                completed: newData.completed,
    77→                content: newData.content,
    78→              });
    79→              return updated;
    80→            });
    81→          } else if (payload.eventType === 'DELETE') {
    82→            const oldData = payload.old as TaskProgress;
    83→            setTaskData((prev) => {
    84→              const updated = new Map(prev);
    85→              updated.delete(oldData.task_key);
    86→              return updated;
    87→            });
    88→          }
    89→        }
    90→      )
    91→      .subscribe();
    92→
    93→    return () => {
    94→      supabase.removeChannel(channel);
    95→    };
    96→  }, [teamId]);
    97→
    98→  const saveTaskContent = useCallback(
    99→    async (taskKey: string, content: string, phase: string) => {
   100→      if (!teamId) return;
   101→
   102→      // Optimistic update
   103→      setTaskData((prev) => {
   104→        const updated = new Map(prev);
   105→        updated.set(taskKey, { completed: true, content });
   106→        return updated;
   107→      });
   108→
   109→      try {
   110→        // Check if task exists
   111→        const { data: existing } = await supabase
   112→          .from('task_progress')
   113→          .select('id')
   114→          .eq('team_id', teamId)
   115→          .eq('task_key', taskKey)
   116→          .single();
   117→
   118→        if (existing) {
   119→          // Update existing
   120→          const { error } = await supabase
   121→            .from('task_progress')
   122→            .update({
   123→              content,
   124→              completed: true,
   125→              completed_at: new Date().toISOString(),
   126→            })
   127→            .eq('team_id', teamId)
   128→            .eq('task_key', taskKey);
   129→
   130→          if (error) throw error;
   131→        } else {
   132→          // Insert new
   133→          const { error } = await supabase.from('task_progress').insert({
   134→            team_id: teamId,
   135→            task_key: taskKey,
   136→            phase: phase as 'phase_1' | 'phase_2' | 'phase_3' | 'phase_4',
   137→            content,
   138→            completed: true,
   139→            completed_at: new Date().toISOString(),
   140→          });
   141→
   142→          if (error) throw error;
   143→        }
   144→
   145→        toast.success('Task saved!');
   146→      } catch (error: any) {
   147→        console.error('Error saving task:', error);
   148→        toast.error('Failed to save task');
   149→        // Revert optimistic update
   150→        setTaskData((prev) => {
   151→          const updated = new Map(prev);
   152→          updated.delete(taskKey);
   153→          return updated;
   154→        });
   155→        throw error;
   156→      }
   157→    },
   158→    [teamId]
   159→  );
   160→
   161→  // Computed values for backward compatibility
   162→  const completedTasks = new Set(
   163→    Array.from(taskData.entries())
   164→      .filter(([_, data]) => data.completed)
   165→      .map(([key]) => key)
   166→  );
   167→
   168→  const taskContents = new Map(
   169→    Array.from(taskData.entries()).map(([key, data]) => [key, data.content])
   170→  );
   171→
   172→  return {
   173→    completedTasks,
   174→    taskContents,
   175→    taskData,
   176→    loading,
   177→    error,
   178→    saveTaskContent,
   179→    refetch: fetchData,
   180→  };
   181→}
