     5→
     6→type Team = Database['public']['Tables']['teams']['Row'];
     7→type TaskProgress = Database['public']['Tables']['task_progress']['Row'];
     8→type TeamMemberName = Database['public']['Tables']['team_member_names']['Row'];
     9→type SprintPhase = Database['public']['Enums']['sprint_phase'];
    10→
    11→export interface TeamWithProgress extends Team {
    12→  taskProgress: TaskProgress[];
    13→  memberNames: string[];
    14→  currentPhase: SprintPhase;
    15→  completedTasks: number;
    16→  totalTasks: number;
    17→  lastActivity: string | null;
    18→  track: string | null;
    19→}
    20→
    21→export interface AdminStats {
    22→  totalTeams: number;
    23→  activeTeams: number;
    24→  teamsPerPhase: Record<SprintPhase, number>;
    25→  averageCompletion: number;
    26→  teamsPerTrack: { startup: number; automation: number; unselected: number };
    27→}
    28→
    29→const phaseOrder: SprintPhase[] = ['waiting', 'phase_1', 'phase_2', 'phase_3', 'phase_4', 'completed'];
    30→
    31→function calculateCurrentPhase(taskProgress: TaskProgress[]): SprintPhase {
    32→  if (taskProgress.length === 0) return 'waiting';
    33→  
    34→  const completedByPhase: Record<string, number> = {};
    35→  const totalByPhase: Record<string, number> = {};
    36→  
    37→  // Count tasks per phase from sprintPhases data
    38→  for (const phase of sprintPhases) {
    39→    totalByPhase[phase.phase] = phase.tasks.length;
    40→    completedByPhase[phase.phase] = 0;
    41→  }
    42→  
    43→  // Count completed tasks
    44→  for (const task of taskProgress) {
    45→    if (task.completed && completedByPhase[task.phase] !== undefined) {
    46→      completedByPhase[task.phase]++;
    47→    }
    48→  }
    49→  
    50→  // Determine current phase
    51→  for (let i = 0; i < sprintPhases.length; i++) {
    52→    const phase = sprintPhases[i];
    53→    const completed = completedByPhase[phase.phase] || 0;
    54→    const total = totalByPhase[phase.phase] || 0;
    55→    
    56→    if (completed < total) {
    57→      return phase.phase as SprintPhase;
    58→    }
    59→  }
    60→  
    61→  return 'completed';
    62→}
    63→
    64→function getTotalTasks(): number {
    65→  return sprintPhases.reduce((acc, phase) => acc + phase.tasks.length, 0);
    66→}
    67→
    68→export function useAdminData() {
    69→  const [teams, setTeams] = useState<TeamWithProgress[]>([]);
    70→  const [stats, setStats] = useState<AdminStats>({
    71→    totalTeams: 0,
    72→    activeTeams: 0,
    73→    teamsPerPhase: {
    74→      waiting: 0,
    75→      phase_1: 0,
    76→      phase_2: 0,
    77→      phase_3: 0,
    78→      phase_4: 0,
    79→      completed: 0,
    80→    },
    81→    averageCompletion: 0,
    82→    teamsPerTrack: { startup: 0, automation: 0, unselected: 0 },
    83→  });
    84→  const [loading, setLoading] = useState(true);
    85→  const [error, setError] = useState<string | null>(null);
    86→
    87→  const fetchData = useCallback(async () => {
    88→    try {
    89→      // Fetch all teams
    90→      const { data: teamsData, error: teamsError } = await supabase
    91→        .from('teams')
    92→        .select('*')
    93→        .order('created_at', { ascending: false });
    94→
    95→      if (teamsError) throw teamsError;
    96→
    97→      // Fetch all task progress
    98→      const { data: progressData, error: progressError } = await supabase
    99→        .from('task_progress')
   100→        .select('*');
   101→
   102→      if (progressError) throw progressError;
   103→
   104→      // Fetch all team member names
   105→      const { data: memberNamesData, error: memberNamesError } = await supabase
   106→        .from('team_member_names')
   107→        .select('*');
   108→
   109→      if (memberNamesError) throw memberNamesError;
   110→
   111→      const totalTasks = getTotalTasks();
   112→      const teamsWithProgress: TeamWithProgress[] = (teamsData || []).map((team) => {
   113→        const teamProgress = (progressData || []).filter((p) => p.team_id === team.id);
   114→        const teamMembers = (memberNamesData || [])
   115→          .filter((m) => m.team_id === team.id)
   116→          .map((m) => m.name);
   117→        const completedTasks = teamProgress.filter((p) => p.completed).length;
   118→        const currentPhase = calculateCurrentPhase(teamProgress);
   119→        
   120→        // Get last activity time
   121→        const lastUpdated = teamProgress
   122→          .map((p) => new Date(p.updated_at).getTime())
   123→          .sort((a, b) => b - a)[0];
   124→
   125→        return {
   126→          ...team,
   127→          taskProgress: teamProgress,
   128→          memberNames: teamMembers,
   129→          currentPhase,
   130→          completedTasks,
   131→          totalTasks,
   132→          lastActivity: lastUpdated ? new Date(lastUpdated).toISOString() : null,
   133→        };
   134→      });
   135→
   136→      // Calculate stats
   137→      const teamsPerPhase: Record<SprintPhase, number> = {
   138→        waiting: 0,
   139→        phase_1: 0,
   140→        phase_2: 0,
   141→        phase_3: 0,
   142→        phase_4: 0,
   143→        completed: 0,
   144→      };
   145→
   146→      const teamsPerTrack = { startup: 0, automation: 0, unselected: 0 };
   147→      let totalCompletion = 0;
   148→      for (const team of teamsWithProgress) {
   149→        teamsPerPhase[team.currentPhase]++;
   150→        totalCompletion += (team.completedTasks / team.totalTasks) * 100;
   151→        if (team.track === 'automation') teamsPerTrack.automation++;
   152→        else if (team.track === 'startup') teamsPerTrack.startup++;
   153→        else teamsPerTrack.unselected++;
   154→      }
   155→
   156→      const activeTeams = teamsWithProgress.filter((t) => t.taskProgress.length > 0).length;
   157→
   158→      setStats({
   159→        totalTeams: teamsWithProgress.length,
   160→        activeTeams,
   161→        teamsPerPhase,
   162→        averageCompletion: teamsWithProgress.length > 0 ? totalCompletion / teamsWithProgress.length : 0,
   163→        teamsPerTrack,
   164→      });
   165→
   166→      setTeams(teamsWithProgress);
   167→      setError(null);
   168→    } catch (err) {
   169→      console.error('Error fetching admin data:', err);
   170→      setError(err instanceof Error ? err.message : 'Failed to fetch data');
   171→    } finally {
   172→      setLoading(false);
   173→    }
   174→  }, []);
   175→
   176→  useEffect(() => {
   177→    fetchData();
   178→
   179→    // Subscribe to realtime updates for task_progress
   180→    const channel = supabase
   181→      .channel('admin-task-progress')
   182→      .on(
   183→        'postgres_changes',
   184→        {
   185→          event: '*',
   186→          schema: 'public',
   187→          table: 'task_progress',
   188→        },
   189→        () => {
   190→          fetchData();
   191→        }
   192→      )
   193→      .on(
   194→        'postgres_changes',
   195→        {
   196→          event: '*',
   197→          schema: 'public',
   198→          table: 'teams',
   199→        },
   200→        () => {
   201→          fetchData();
   202→        }
   203→      )
   204→      .subscribe();
   205→
   206→    return () => {
   207→      supabase.removeChannel(channel);
   208→    };
   209→  }, [fetchData]);
   210→
   211→  return { teams, stats, loading, error, refetch: fetchData };
   212→}
