    40→export function useCustomerSegments(teamId: string | undefined) {
    41→  const [segments, setSegments] = useState<SegmentData[]>([]);
    42→  const [loading, setLoading] = useState(true);
    43→  const [error, setError] = useState<string | null>(null);
    44→
    45→  // Fetch segments from database
    46→  const fetchSegments = useCallback(async () => {
    47→    if (!teamId) {
    48→      setSegments([]);
    49→      setLoading(false);
    50→      return;
    51→    }
    52→
    53→    try {
    54→      const { data, error: fetchError } = await supabase
    55→        .from('customer_segments')
    56→        .select('*')
    57→        .eq('team_id', teamId)
    58→        .order('created_at', { ascending: true });
    59→
    60→      if (fetchError) {
    61→        console.error('Error fetching segments:', fetchError);
    62→        setError(fetchError.message);
    63→        return;
    64→      }
    65→
    66→      setSegments((data || []).map(toSegmentData));
    67→    } catch (err) {
    68→      console.error('Error fetching segments:', err);
    69→      setError(err instanceof Error ? err.message : 'Unknown error');
    70→    } finally {
    71→      setLoading(false);
    72→    }
    73→  }, [teamId]);
    74→
    75→  // Initial fetch
    76→  useEffect(() => {
    77→    fetchSegments();
    78→  }, [fetchSegments]);
    79→
    80→  // Real-time subscription
    81→  useEffect(() => {
    82→    if (!teamId) return;
    83→
    84→    const channel = supabase
    85→      .channel(`customer_segments_${teamId}`)
    86→      .on(
    87→        'postgres_changes',
    88→        {
    89→          event: '*',
    90→          schema: 'public',
    91→          table: 'customer_segments',
    92→          filter: `team_id=eq.${teamId}`,
    93→        },
    94→        (payload) => {
    95→          if (payload.eventType === 'INSERT') {
    96→            const newSegment = toSegmentData(payload.new as DatabaseSegment);
    97→            setSegments((prev) => {
    98→              // Avoid duplicates
    99→              if (prev.some((s) => s.id === newSegment.id)) return prev;
   100→              return [...prev, newSegment];
   101→            });
   102→          } else if (payload.eventType === 'UPDATE') {
   103→            const updatedSegment = toSegmentData(payload.new as DatabaseSegment);
   104→            setSegments((prev) =>
   105→              prev.map((s) => (s.id === updatedSegment.id ? updatedSegment : s))
   106→            );
   107→          } else if (payload.eventType === 'DELETE') {
   108→            const deletedId = (payload.old as { id: string }).id;
   109→            setSegments((prev) => prev.filter((s) => s.id !== deletedId));
   110→          }
   111→        }
   112→      )
   113→      .subscribe();
   114→
   115→    return () => {
   116→      supabase.removeChannel(channel);
   117→    };
   118→  }, [teamId]);
   119→
   120→  // Add a new segment
   121→  const addSegment = useCallback(
   122→    async (segment: Omit<SegmentData, 'id'>): Promise<SegmentData | null> => {
   123→      if (!teamId) {
   124→        toast.error('No team selected');
   125→        return null;
   126→      }
   127→
   128→      const dbData = toDbFormat(segment as SegmentData, teamId);
   129→
   130→      const { data, error: insertError } = await supabase
   131→        .from('customer_segments')
   132→        .insert(dbData)
   133→        .select()
   134→        .single();
   135→
   136→      if (insertError) {
   137→        console.error('Error adding segment:', insertError);
   138→        toast.error('Failed to save segment');
   139→        return null;
   140→      }
   141→
   142→      const newSegment = toSegmentData(data);
   143→      // Optimistic update handled by realtime, but add immediately for responsiveness
   144→      setSegments((prev) => {
   145→        if (prev.some((s) => s.id === newSegment.id)) return prev;
   146→        return [...prev, newSegment];
   147→      });
   148→
   149→      return newSegment;
   150→    },
   151→    [teamId]
   152→  );
   153→
   154→  // Update an existing segment
   155→  const updateSegment = useCallback(
   156→    async (id: string, updates: Partial<SegmentData>): Promise<boolean> => {
   157→      if (!teamId) return false;
   158→
   159→      const dbUpdates: Record<string, unknown> = {};
   160→      if (updates.name !== undefined) dbUpdates.name = updates.name;
   161→      if (updates.companyType !== undefined) dbUpdates.company_type = updates.companyType;
   162→      if (updates.jobTitles !== undefined) dbUpdates.job_titles = updates.jobTitles;
   163→      if (updates.whyTheyCare !== undefined) dbUpdates.why_they_care = updates.whyTheyCare;
   164→      if (updates.isCustom !== undefined) dbUpdates.is_custom = updates.isCustom;
   165→
   166→      const { error: updateError } = await supabase
   167→        .from('customer_segments')
   168→        .update(dbUpdates)
   169→        .eq('id', id)
   170→        .eq('team_id', teamId);
   171→
   172→      if (updateError) {
   173→        console.error('Error updating segment:', updateError);
   174→        toast.error('Failed to update segment');
   175→        return false;
   176→      }
   177→
   178→      return true;
   179→    },
   180→    [teamId]
   181→  );
   182→
   183→  // Delete a segment
   184→  const deleteSegment = useCallback(
   185→    async (id: string): Promise<boolean> => {
   186→      if (!teamId) return false;
   187→
   188→      // Optimistic update
   189→      setSegments((prev) => prev.filter((s) => s.id !== id));
   190→
   191→      const { error: deleteError } = await supabase
   192→        .from('customer_segments')
   193→        .delete()
   194→        .eq('id', id)
   195→        .eq('team_id', teamId);
   196→
   197→      if (deleteError) {
   198→        console.error('Error deleting segment:', deleteError);
   199→        toast.error('Failed to delete segment');
   200→        // Refetch to restore state
   201→        fetchSegments();
   202→        return false;
   203→      }
   204→
   205→      return true;
   206→    },
   207→    [teamId, fetchSegments]
   208→  );
   209→
   210→  // Duplicate a segment
   211→  const duplicateSegment = useCallback(
   212→    async (segment: SegmentData): Promise<SegmentData | null> => {
   213→      const newSegment = {
   214→        name: `${segment.name} (Copy)`,
   215→        companyType: segment.companyType,
   216→        jobTitles: [...segment.jobTitles],
   217→        whyTheyCare: segment.whyTheyCare,
   218→        isCustom: true, // Duplicates are considered custom
   219→      };
   220→
   221→      return addSegment(newSegment);
   222→    },
   223→    [addSegment]
   224→  );
   225→
   226→  return {
   227→    segments,
   228→    loading,
   229→    error,
   230→    addSegment,
   231→    updateSegment,
   232→    deleteSegment,
   233→    duplicateSegment,
   234→    refetch: fetchSegments,
   235→  };
   236→}
